import{_ as d,o as r,c as a,a5 as e}from"./chunks/framework.B5tqjWbr.js";const V=JSON.parse('{"title":"SVPWM 矢量合成仿真（参考知乎：SVPWM理论与实践）","description":"","frontmatter":{"title":"SVPWM 矢量合成仿真（参考知乎：SVPWM理论与实践）","date":"2026-07-02T00:00:00.000Z","section":"电机控制","chapter":"02-Simulations","chapterTitle":"仿真专题","category":"电机控制","tags":["imported"],"source":"motor","sourcePath":"frontend/src/components/simulations/SVPWMSim.vue","status":"learning","visibility":"public","summary":"Imported from frontend/src/components/simulations/SVPWMSim.vue","chapterOrder":20},"headers":[],"relativePath":"content/motor/simulations/SVPWMSim.md","filePath":"content/motor/simulations/SVPWMSim.md","lastUpdated":null}'),o={name:"content/motor/simulations/SVPWMSim.md"};function s(n,t,i,m,p,h){return r(),a("div",null,[...t[0]||(t[0]=[e('<h1 id="svpwm-矢量合成仿真-参考知乎-svpwm理论与实践" tabindex="-1">SVPWM 矢量合成仿真（参考知乎：SVPWM理论与实践） <a class="header-anchor" href="#svpwm-矢量合成仿真-参考知乎-svpwm理论与实践" aria-label="Permalink to &quot;SVPWM 矢量合成仿真（参考知乎：SVPWM理论与实践）&quot;">​</a></h1><h4 id="svpwm-矢量合成仿真-参考知乎-svpwm理论与实践-1" tabindex="-1">SVPWM 矢量合成仿真（参考知乎：SVPWM理论与实践） <a class="header-anchor" href="#svpwm-矢量合成仿真-参考知乎-svpwm理论与实践-1" aria-label="Permalink to &quot;SVPWM 矢量合成仿真（参考知乎：SVPWM理论与实践）&quot;">​</a></h4><h2 id="svpwm-完整算法流程-关键图表说明" tabindex="-1">SVPWM 完整算法流程 &amp; 关键图表说明 <a class="header-anchor" href="#svpwm-完整算法流程-关键图表说明" aria-label="Permalink to &quot;SVPWM 完整算法流程 &amp; 关键图表说明&quot;">​</a></h2><table tabindex="0"><thead><tr><th>特性</th><th>七段式</th><th>五段式</th></tr></thead><tbody><tr><td>每周期段数</td><td>7 (V0→V1→V2→V7→V2→V1→V0)</td><td>5</td></tr><tr><td>零矢量分布</td><td>V0+V7 对称(图13)</td><td>交替舍弃</td></tr><tr><td>PWM对称性</td><td>完全中心对称(图15)</td><td>中心对称</td></tr><tr><td>电流纹波(图16)</td><td>最小(Δt减半)</td><td>较大(~1.5×)</td></tr><tr><td>开关损耗</td><td>较高(每相2次)</td><td>降低~33%</td></tr></tbody></table><p>**图5/12 矢量合成区：**六边形顶点为6个非零基本矢量(V₁~V₆)，中心为零矢量(V₀/V₇)。绿色虚线=内切圆(m≤1线性区)，橙色虚线=外接圆(m≤1.155过调制区)。Vref为待合成的参考矢量，通过相邻两矢量投影分解得到作用时间。</p><p>**图8/9 三相正弦：**三相电压uₐ/u_b/u_c互差120°，合成空间矢量Vδ幅值为相电压1.5倍，以电角速度ωₑ旋转。</p><p>**图22/25 三角波载波比较法：**三角波峰值=Ts/2，Tcmp1/Tcmp2/Tcmp3为三相开关切换时间。当三角波值 &gt; TcmpX时对应相PWM输出高电平(上管导通)，否则低电平。下方完整显示各时段的时间标签、矢量名和开关状态。</p><p>**表2/图14 开关顺序：**6扇区各有独立切换顺序(0-4-6-7-6-4-0等)，原则是每次只变一相开关状态。当前扇区高亮显示完整 8 步序列。</p><p>**图16 对称性优势：**七段式将零矢量V₇置于中间→相电压关于Ts/2对称→电流纹波Δi∝V·Δt/L中Δt减半→纹波≈½→转矩脉动和噪音显著减小。</p><p>**死区时间 (Dead-Time)：**为防止上下桥臂直通(shoot-through)，上管关断后需延时Tdead才开通下管(反之亦然)。导致实际输出电压损失 = Vdc × (Tdead/Ts)，低速时畸变显著需补偿。图中红色影区=上升沿被延迟的份额。</p><h2 id="📋-电控知识体系中缺失的关键内容-建议后续补充" tabindex="-1">📋 电控知识体系中缺失的关键内容（建议后续补充） <a class="header-anchor" href="#📋-电控知识体系中缺失的关键内容-建议后续补充" aria-label="Permalink to &quot;📋 电控知识体系中缺失的关键内容（建议后续补充）&quot;">​</a></h2><table tabindex="0"><thead><tr><th>#</th><th>缺失内容</th><th>为何不可或缺</th></tr></thead><tbody><tr><td>1</td><td><strong>Clarke/Park 坐标变换</strong> abc→αβ→dq</td><td>FOC 核心：将三相交流量变换为旋转坐标系直流分量，是电流环 PI 控制的前提</td></tr><tr><td>2</td><td><strong>电流采样时序</strong></td><td>ADC 在 PWM 周期中心(V0段)采样可避开开关噪声，采样误差直接影响控制精度</td></tr><tr><td>3</td><td><strong>过调制策略</strong> (m&gt;1.155)</td><td>六边形顶点以外区域需电压钳位/角度跟随，影响弱磁区最大输出转矩</td></tr><tr><td>4</td><td><strong>PI 电流调节器</strong> dq电流环设计</td><td>解耦控制 + 前馈补偿 + anti-windup，是 FOC 内环核心</td></tr><tr><td>5</td><td><strong>位置/速度观测器</strong> (SMO/Luenberger)</td><td>无传感器 FOC 必需：从电流/电压估算反电势→转子位置→速度</td></tr><tr><td>6</td><td><strong>弱磁控制 + MTPA/MTPV</strong></td><td>高速区利用负Id弱磁扩展转速范围，MTPA最大化转矩/电流比</td></tr><tr><td>7</td><td><strong>THD 谐波分析</strong> SVPWM vs SPWM</td><td>量化调制策略的电流波形质量，影响铁损和转矩脉动评估</td></tr><tr><td>8</td><td><strong>启动定位/预定位</strong></td><td>初始转子位置检测(高频注入/IPD)，影响启动转矩和反转风险</td></tr><tr><td>9</td><td><strong>速度环 + 负载转矩观测器</strong></td><td>外环速度控制 + 负载扰动前馈补偿，提升动态刚度</td></tr><tr><td>10</td><td><strong>死区补偿策略</strong></td><td>基于电流极性判断的电压前馈补偿，消除低速电流钳位和转矩脉动</td></tr></tbody></table>',12)])])}const c=d(o,[["render",s]]);export{V as __pageData,c as default};
